blocks.function:
const report = JSON.parse($PreScan.result);
const found = [];
for (const result of (report.Results || [])) {
    if (result.Class !== "os-pkgs") continue;
    for (const vuln of (result.Vulnerabilities || [])) {
        if (vuln.FixedVersion) {
            found.push({id: vuln.VulnerabilityID, pkg: vuln.PkgName});
        }
    }
}
$pre_vuln_ids = found.map(f => f.id);
$vulnerable_packages = [...new Set(found.map(f => f.pkg))].sort();

then.function:
const postReport = JSON.parse($PostScanJson.result);
const postFound = [];
for (const result of (postReport.Results || [])) {
    if (result.Class !== "os-pkgs") continue;
    for (const vuln of (result.Vulnerabilities || [])) {
        if (vuln.FixedVersion) {
            postFound.push(vuln.VulnerabilityID);
        }
    }
}
const postIds = new Set(postFound);
const preIds = new Set($pre_vuln_ids);
$resolved_ids = $pre_vuln_ids.filter(id => !postIds.has(id));
$still_present_ids = $pre_vuln_ids.filter(id => postIds.has(id));
$remediation_ok = $still_present_ids.length === 0;

$patched_post_scan = $PostScanCdx.result.replace(/"specVersion"\s*:\s*"[^"]*"/, '"specVersion":"1.5"');
$metadata_str = JSON.stringify({
    scanner_name: "trivy",
    application_name: $application_name,
    application_version: $application_version
});

const found = ($FindActions.result && $FindActions.result.actions) || [];
$action_updates = found.map(a => ({
    action_id: a.actions_identifier,
    status: $remediation_ok ? "success" : "failed",
    comments: "Auto-updated by Remediate_SSH_Host"
}));
